module  omsp_clock_gate (
    gclk,                      
    clk,                       
    enable,                    
    scan_enable                
);
output         gclk;           
input          clk;            
input          enable;         
input          scan_enable;    
wire    enable_in =   (enable | scan_enable);
reg     enable_latch;
always @(clk or enable_in)
  if (~clk)
    enable_latch <= enable_in;
  wire temp1_clk = clk;
  wire temp2_enable_latch = enable_latch;
  assign  gclk      =  (temp1_clk & temp2_enable_latch);
endmodule
